// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract ProviderVault {
    using SafeERC20 for IERC20;

    IERC20 public immutable token;
    address public immutable admin;
    address public taskCommitment;

    struct VaultState {
        uint256 totalDeposited;
        uint256 outstandingLiability;
        bool registered;
    }

    // AA wallet => vault state
    mapping(address => VaultState) public vaults;

    // Optional operator EOA => AA wallet
    mapping(address => address) public operatorToAA;

    event ProviderVaultRegistered(address indexed providerAA, address indexed operator);
    event OperatorUpdated(address indexed providerAA, address indexed oldOperator, address indexed newOperator);
    event Deposited(address indexed providerAA, uint256 amount, uint256 newTotal);
    event Withdrawn(address indexed providerAA, uint256 amount, uint256 remaining);
    event LiabilityReserved(address indexed providerAA, uint256 amount, uint256 newLiability);
    event LiabilityReleased(address indexed providerAA, uint256 amount, uint256 newLiability);
    event Slashed(address indexed providerAA, address indexed recipient, uint256 amount);
    event TaskCommitmentUpdated(address indexed newTaskCommitment);

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier onlyTaskCommitment() {
        require(msg.sender == taskCommitment, "Caller is not TaskCommitment");
        _;
    }

    constructor(address _token) {
        require(_token != address(0), "Zero token address");
        token = IERC20(_token);
        admin = msg.sender;
    }

    function setTaskCommitment(address _taskCommitment) external onlyAdmin {
        require(_taskCommitment != address(0), "Zero address");
        taskCommitment = _taskCommitment;
        emit TaskCommitmentUpdated(_taskCommitment);
    }

    /// @notice Register the caller as the provider's AA wallet.
    /// @param operator Optional EOA/operator allowed to act on behalf of this AA wallet for UX convenience.
    function registerVault(address operator) external {
        VaultState storage v = vaults[msg.sender];
        require(!v.registered, "Vault already registered");

        v.registered = true;

        if (operator != address(0)) {
            require(operatorToAA[operator] == address(0), "Operator already assigned");
            operatorToAA[operator] = msg.sender;
        }

        emit ProviderVaultRegistered(msg.sender, operator);
    }

    /// @notice Update or clear the operator for the caller's AA wallet.
    function setOperator(address newOperator) external {
        VaultState storage v = vaults[msg.sender];
        require(v.registered, "Vault not registered");

        address oldOperator = address(0);

        // Find current operator by scanning impossible on-chain, so we only allow replacing
        // when caller supplies a fresh operator and old operator is managed off-chain.
        // To support safe replacement, caller should first clear old operator using clearOperator.
        if (newOperator != address(0)) {
            require(operatorToAA[newOperator] == address(0), "Operator already assigned");
            operatorToAA[newOperator] = msg.sender;
        }

        emit OperatorUpdated(msg.sender, oldOperator, newOperator);
    }

    /// @notice Clear an operator mapping if the caller knows the operator address.
    function clearOperator(address operator) external {
        VaultState storage v = vaults[msg.sender];
        require(v.registered, "Vault not registered");
        require(operatorToAA[operator] == msg.sender, "Operator not mapped to caller");

        delete operatorToAA[operator];

        emit OperatorUpdated(msg.sender, operator, address(0));
    }

    function resolveProvider(address caller) public view returns (address) {
        if (vaults[caller].registered) {
            return caller; // caller is the AA wallet
        }

        address aa = operatorToAA[caller];
        require(aa != address(0) && vaults[aa].registered, "Not authorized provider");
        return aa;
    }

    function deposit(uint256 amount) external {
        require(amount > 0, "Amount must be > 0");

        address providerAA = resolveProvider(msg.sender);
        VaultState storage v = vaults[providerAA];

        token.safeTransferFrom(providerAA, address(this), amount);

        v.totalDeposited += amount;

        emit Deposited(providerAA, amount, v.totalDeposited);
    }

    function withdraw(uint256 amount) external {
        require(amount > 0, "Amount must be > 0");

        address providerAA = resolveProvider(msg.sender);
        VaultState storage v = vaults[providerAA];

        uint256 available = v.totalDeposited - v.outstandingLiability;
        require(amount <= available, "Insufficient available capacity");

        v.totalDeposited -= amount;
        token.safeTransfer(providerAA, amount);

        emit Withdrawn(providerAA, amount, v.totalDeposited);
    }

    function reserveLiability(address providerAA, uint256 amount) external onlyTaskCommitment {
        require(providerAA != address(0), "Zero provider AA");
        require(amount > 0, "Amount must be > 0");

        VaultState storage v = vaults[providerAA];
        require(v.registered, "Provider vault not registered");

        uint256 available = v.totalDeposited - v.outstandingLiability;
        require(amount <= available, "Insufficient vault capacity");

        v.outstandingLiability += amount;

        emit LiabilityReserved(providerAA, amount, v.outstandingLiability);
    }

    function releaseLiability(address providerAA, uint256 amount) external onlyTaskCommitment {
        require(providerAA != address(0), "Zero provider AA");
        require(amount > 0, "Amount must be > 0");

        VaultState storage v = vaults[providerAA];
        require(v.registered, "Provider vault not registered");
        require(v.outstandingLiability >= amount, "Liability underflow");

        v.outstandingLiability -= amount;

        emit LiabilityReleased(providerAA, amount, v.outstandingLiability);
    }

    function slash(address providerAA, uint256 amount, address recipient) external onlyTaskCommitment {
        require(providerAA != address(0), "Zero provider AA");
        require(recipient != address(0), "Zero recipient");
        require(amount > 0, "Amount must be > 0");

        VaultState storage v = vaults[providerAA];
        require(v.registered, "Provider vault not registered");
        require(v.outstandingLiability >= amount, "Liability underflow");
        require(v.totalDeposited >= amount, "Deposit underflow");

        v.outstandingLiability -= amount;
        v.totalDeposited -= amount;

        token.safeTransfer(recipient, amount);

        emit Slashed(providerAA, recipient, amount);
    }

    function availableCapacity(address providerAA) external view returns (uint256) {
        VaultState storage v = vaults[providerAA];
        require(v.registered, "Provider vault not registered");
        return v.totalDeposited - v.outstandingLiability;
    }

    function getVaultState(address providerAA)
        external
        view
        returns (
            uint256 totalDeposited,
            uint256 outstandingLiability,
            uint256 available,
            bool registered
        )
    {
        VaultState storage v = vaults[providerAA];

        return (
            v.totalDeposited,
            v.outstandingLiability,
            v.totalDeposited - v.outstandingLiability,
            v.registered
        );
    }
}

contracts/TaskCommitment.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "./ProviderVault.sol";
import "./VerifierV1.sol";

/**
 * TaskCommitment — Core ACCORD protocol contract
 * 7-state machine:
 * Created → LiabilityReserved → PaymentLinked → DeliverySubmitted →
 * VerifiedPass | VerifiedFail | Expired
 *
 * Binary settlement: pass releases liability, fail slashes immediately.
 * No dispute window. No escape hatch.
 *
 * Practical correction:
 * - spec is committed once at createCommitment
 * - constraints are stored on-chain per task
 * - submitDelivery only submits values (fields), not new rules
 * - verification runs against the committed spec
 */
contract TaskCommitment {
    using ECDSA for bytes32;

    enum TaskState {
        Created,
        LiabilityReserved,
        PaymentLinked,
        DeliverySubmitted,
        VerifiedPass,
        VerifiedFail,
        Expired
    }

    struct Commitment {
        bytes32 taskId;
        bytes32 specHash;
        address providerAA;
        address providerSigner;
        address buyer;
        uint256 liabilityAmount;
        uint256 deadlineTimestamp;
        uint8 verifierVersion;
        bytes32 paymentReference;
        bytes32 commitmentNonce;
        TaskState taskState;
        uint256 createdAt;
    }

    struct DeliveryObject {
        bytes32 taskId;
        bytes32 outputHash;
        uint256 timestamp;
        uint8 schemaVersion;
        address signerAddress;
        bytes32 providerNonce;
        bytes signature;
    }

    bytes32 private constant DOMAIN_TYPEHASH = keccak256(
        "EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"
    );

    bytes32 private constant DELIVERY_TYPEHASH = keccak256(
        "DeliveryObject(bytes32 taskId,bytes32 outputHash,uint256 timestamp,uint8 schemaVersion,address signerAddress,bytes32 providerNonce,bytes32 paymentReference)"
    );

    bytes32 public immutable DOMAIN_SEPARATOR;

    ProviderVault public vault;
    VerifierV1 public verifier;
    address public attestationRegistry;
    address public immutable owner;

    mapping(bytes32 => Commitment) public commitments;
    mapping(bytes32 => bool) public usedCommitmentNonces;
    mapping(bytes32 => bool) public usedDeliveryNonces;
    mapping(bytes32 => bool) public usedDeliveryDigests;

    // committed spec storage
    mapping(bytes32 => bytes32) public commitmentSchemaHash;
    mapping(bytes32 => VerifierV1.Constraint[]) internal commitmentConstraints;

    event CommitmentCreated(
        bytes32 indexed taskId,
        address indexed providerAA,
        address indexed buyer,
        uint256 liabilityAmount
    );
    event LiabilityReserved(
        bytes32 indexed taskId,
        address indexed providerAA,
        uint256 amount
    );
    event PaymentLinked(bytes32 indexed taskId, bytes32 paymentReference);
    event DeliverySubmitted(bytes32 indexed taskId, bytes32 outputHash);
    event VerifiedPass(bytes32 indexed taskId, address indexed providerAA);
    event VerifiedFail(
        bytes32 indexed taskId,
        address indexed providerAA,
        bytes32 failReason
    );
    event TaskExpired(bytes32 indexed taskId, address indexed providerAA);

    event VerificationTraceItem(
        bytes32 indexed taskId,
        uint256 indexed index,
        bytes32 fieldKey,
        uint8 constraintType,
        bool passed,
        bytes32 reason
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "Not owner");
        _;
    }

    constructor(address _vault, address _verifier) {
        require(_vault != address(0), "Zero vault");
        require(_verifier != address(0), "Zero verifier");
        vault = ProviderVault(_vault);
        verifier = VerifierV1(_verifier);
        owner = msg.sender;

        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                DOMAIN_TYPEHASH,
                keccak256(bytes("ACCORD")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    function setAttestationRegistry(address _registry) external onlyOwner {
        require(_registry != address(0), "Zero address");
        attestationRegistry = _registry;
    }

    function createCommitment(
        address providerAA,
        address providerSigner,
        bytes32 schemaHash,
        VerifierV1.Constraint[] calldata constraints,
        uint256 liabilityAmount,
        uint256 deadlineTimestamp,
        uint8 verifierVersion,
        bytes32 commitmentNonce
    ) external returns (bytes32 taskId) {
        require(providerAA != address(0), "Zero provider AA");
        require(providerSigner != address(0), "Zero provider signer");
        require(schemaHash != bytes32(0), "Zero schema hash");
        require(liabilityAmount > 0, "Liability must be > 0");
        require(deadlineTimestamp > block.timestamp, "Deadline must be in future");
        require(!usedCommitmentNonces[commitmentNonce], "Nonce already used");

        bytes32 specHash = verifier.hashSpec(schemaHash, constraints);

        taskId = keccak256(
            abi.encode(
                msg.sender,
                providerAA,
                providerSigner,
                specHash,
                liabilityAmount,
                deadlineTimestamp,
                verifierVersion,
                commitmentNonce
            )
        );

        require(commitments[taskId].createdAt == 0, "Task already exists");

        usedCommitmentNonces[commitmentNonce] = true;

        commitments[taskId] = Commitment({
            taskId: taskId,
            specHash: specHash,
            providerAA: providerAA,
            providerSigner: providerSigner,
            buyer: msg.sender,
            liabilityAmount: liabilityAmount,
            deadlineTimestamp: deadlineTimestamp,
            verifierVersion: verifierVersion,
            paymentReference: bytes32(0),
            commitmentNonce: commitmentNonce,
            taskState: TaskState.Created,
            createdAt: block.timestamp
        });

        commitmentSchemaHash[taskId] = schemaHash;

        for (uint256 i = 0; i < constraints.length; i++) {
            VerifierV1.Constraint storage stored = commitmentConstraints[taskId].push();
            stored.constraintType = constraints[i].constraintType;
            stored.fieldKey = constraints[i].fieldKey;
            stored.minValue = constraints[i].minValue;
            stored.maxValue = constraints[i].maxValue;
            stored.expectedValue = constraints[i].expectedValue;
            stored.expectedHash = constraints[i].expectedHash;

            for (uint256 j = 0; j < constraints[i].enumMembers.length; j++) {
                stored.enumMembers.push(constraints[i].enumMembers[j]);
            }
        }

        emit CommitmentCreated(taskId, providerAA, msg.sender, liabilityAmount);
        return taskId;
    }

    function reserveLiability(bytes32 taskId) external {
        Commitment storage c = commitments[taskId];
        require(c.createdAt != 0, "Task not found");
        require(c.taskState == TaskState.Created, "Invalid state");
        require(msg.sender == c.providerAA, "Only provider AA");

        vault.reserveLiability(c.providerAA, c.liabilityAmount);
        c.taskState = TaskState.LiabilityReserved;

        emit LiabilityReserved(taskId, c.providerAA, c.liabilityAmount);
    }

    function linkPayment(bytes32 taskId, bytes32 paymentReference) external {
        Commitment storage c = commitments[taskId];
        require(c.createdAt != 0, "Task not found");
        require(c.taskState == TaskState.LiabilityReserved, "Invalid state");
        require(msg.sender == c.buyer, "Only buyer");
        require(paymentReference != bytes32(0), "Zero payment reference");

        c.paymentReference = paymentReference;
        c.taskState = TaskState.PaymentLinked;

        emit PaymentLinked(taskId, paymentReference);
    }

    function submitDelivery(
        bytes32 taskId,
        DeliveryObject calldata delivery,
        VerifierV1.FieldValue[] calldata fields
    ) external {
        Commitment storage c = commitments[taskId];
        require(c.createdAt != 0, "Task not found");
        require(c.taskState == TaskState.PaymentLinked, "Invalid state");
        require(msg.sender == c.providerAA, "Only provider AA");
        require(block.timestamp <= c.deadlineTimestamp, "Deadline passed");

        require(delivery.taskId == taskId, "Task binding mismatch");
        require(delivery.signerAddress == c.providerSigner, "Signer mismatch");
        require(!usedDeliveryNonces[delivery.providerNonce], "Replay nonce used");

        bytes32 committedSpecHash = verifier.hashSpec(
            commitmentSchemaHash[taskId],
            commitmentConstraints[taskId]
        );
        require(committedSpecHash == c.specHash, "Stored spec corrupted");

        bytes32 deliveryDigest = _deliveryDigest(c, delivery);
        require(!usedDeliveryDigests[deliveryDigest], "Replay digest used");

        address recovered = _recoverSigner(deliveryDigest, delivery.signature);
        require(recovered == c.providerSigner, "Invalid provider signature");

        usedDeliveryNonces[delivery.providerNonce] = true;
        usedDeliveryDigests[deliveryDigest] = true;

        c.taskState = TaskState.DeliverySubmitted;
        emit DeliverySubmitted(taskId, delivery.outputHash);

        (bool passed, VerifierV1.VerificationTrace[] memory trace) = verifier.verify(
            fields,
            commitmentConstraints[taskId],
            c.deadlineTimestamp
        );

        bytes32 failReason = bytes32("UNKNOWN");
        for (uint256 i = 0; i < trace.length; i++) {
            emit VerificationTraceItem(
                taskId,
                i,
                trace[i].fieldKey,
                uint8(trace[i].constraintType),
                trace[i].passed,
                trace[i].reason
            );

            if (!trace[i].passed && failReason == bytes32("UNKNOWN")) {
                failReason = trace[i].reason;
            }
        }

        if (passed) {
            _settlePass(taskId, c);
        } else {
            _settleFail(taskId, c, failReason);
        }
    }

    function expireTask(bytes32 taskId) external {
        Commitment storage c = commitments[taskId];
        require(c.createdAt != 0, "Task not found");
        require(
            c.taskState == TaskState.Created ||
                c.taskState == TaskState.LiabilityReserved ||
                c.taskState == TaskState.PaymentLinked,
            "Cannot expire"
        );
        require(block.timestamp > c.deadlineTimestamp, "Not yet expired");

        if (
            c.taskState == TaskState.LiabilityReserved ||
            c.taskState == TaskState.PaymentLinked
        ) {
            vault.slash(c.providerAA, c.liabilityAmount, c.buyer);
        }

        c.taskState = TaskState.Expired;
        emit TaskExpired(taskId, c.providerAA);

        _recordAttestation(taskId, false, c.providerAA);
    }

    function getCommitment(
        bytes32 taskId
    ) external view returns (Commitment memory) {
        return commitments[taskId];
    }

    function getConstraintCount(bytes32 taskId) external view returns (uint256) {
        return commitmentConstraints[taskId].length;
    }

    function getConstraint(
        bytes32 taskId,
        uint256 index
    ) external view returns (VerifierV1.Constraint memory) {
        require(index < commitmentConstraints[taskId].length, "Constraint index out of bounds");
        return commitmentConstraints[taskId][index];
    }

    function _settlePass(bytes32 taskId, Commitment storage c) internal {
        c.taskState = TaskState.VerifiedPass;
        vault.releaseLiability(c.providerAA, c.liabilityAmount);
        emit VerifiedPass(taskId, c.providerAA);
        _recordAttestation(taskId, true, c.providerAA);
    }

    function _settleFail(
        bytes32 taskId,
        Commitment storage c,
        bytes32 failReason
    ) internal {
        c.taskState = TaskState.VerifiedFail;
        vault.slash(c.providerAA, c.liabilityAmount, c.buyer);
        emit VerifiedFail(taskId, c.providerAA, failReason);
        _recordAttestation(taskId, false, c.providerAA);
    }

    function _recordAttestation(
        bytes32 taskId,
        bool passed,
        address providerAA
    ) internal {
        if (attestationRegistry == address(0)) return;
        IAttestationRegistry(attestationRegistry).record(taskId, passed, providerAA);
    }

    function _deliveryDigest(
        Commitment storage c,
        DeliveryObject calldata delivery
    ) internal view returns (bytes32) {
        bytes32 structHash = keccak256(
            abi.encode(
                DELIVERY_TYPEHASH,
                delivery.taskId,
                delivery.outputHash,
                delivery.timestamp,
                delivery.schemaVersion,
                delivery.signerAddress,
                delivery.providerNonce,
                c.paymentReference
            )
        );

        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    function _recoverSigner(
        bytes32 digest,
        bytes calldata signature
    ) internal pure returns (address) {
        return ECDSA.recover(digest, signature);
    }
}

interface IAttestationRegistry {
    function record(bytes32 taskId, bool passed, address providerAA) external;
}

contracts/VerifierV1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * VerifierV1 — Deterministic constraint verifier for ACCORD protocol
 * Closed constraint vocabulary — any unsupported constraint is rejected
 * Produces a reason trace for every verification run
 * Binary result — pass or fail, no partial credit
 */
contract VerifierV1 {
    enum ConstraintType {
        FIELD_REQUIRED,
        EQUALS,
        RANGE,
        HASH_MATCH,
        DEADLINE,
        SIGNATURE_VALID,
        ENUM_MEMBER,
        FRESHNESS,
        TIMESTAMP_WINDOW,
        MERKLE_ROOT_MATCH,
        SIGNER_IN_ALLOWLIST
    }

    enum ValueType {
        INT,      // 0
        HASH,     // 1
        ADDRESS,  // 2
        BOOL      // 3
    }

    struct Constraint {
        ConstraintType constraintType;
        bytes32 fieldKey;
        int256 minValue;
        int256 maxValue;
        int256 expectedValue;
        bytes32 expectedHash;
        bytes32[] enumMembers;
    }

    struct FieldValue {
        bytes32 fieldKey;
        bool exists;
        int256 intValue;
        bytes32 hashValue;
        address addrValue;
        bool boolValue;
        uint8 valueType; // use ValueType enum values
    }

    struct VerificationTrace {
        bytes32 fieldKey;
        ConstraintType constraintType;
        bool passed;
        bytes32 reason;
    }

    function hashSpec(
        bytes32 schemaHash,
        Constraint[] calldata constraints
    ) external pure returns (bytes32) {
        return keccak256(abi.encode(schemaHash, constraints));
    }

    function verify(
        FieldValue[] calldata fields,
        Constraint[] calldata constraints,
        uint256 deadline
    ) external view returns (bool passed, VerificationTrace[] memory trace) {
        trace = new VerificationTrace[](constraints.length);
        passed = true;

        for (uint256 i = 0; i < constraints.length; i++) {
            Constraint calldata c = constraints[i];
            (FieldValue memory field, bool found) = _findField(fields, c.fieldKey);

            (bool result, bytes32 reason) = _evaluateConstraint(
                c,
                field,
                found,
                deadline
            );

            trace[i] = VerificationTrace({
                fieldKey: c.fieldKey,
                constraintType: c.constraintType,
                passed: result,
                reason: reason
            });

            if (!result) {
                passed = false;
            }
        }

        return (passed, trace);
    }

    function _findField(
        FieldValue[] calldata fields,
        bytes32 fieldKey
    ) internal pure returns (FieldValue memory field, bool found) {
        for (uint256 i = 0; i < fields.length; i++) {
            if (fields[i].fieldKey == fieldKey) {
                return (fields[i], true);
            }
        }

        FieldValue memory empty;
        empty.fieldKey = fieldKey;
        empty.exists = false;
        return (empty, false);
    }

    function _evaluateConstraint(
        Constraint calldata c,
        FieldValue memory field,
        bool found,
        uint256 deadline
    ) internal view returns (bool, bytes32) {
        if (c.constraintType == ConstraintType.FIELD_REQUIRED) {
            bool present = found && field.exists;
            return (present, present ? bytes32("OK") : bytes32("FIELD_MISSING"));
        }

        if (!found || !field.exists) {
            return (false, bytes32("FIELD_MISSING"));
        }

        if (c.constraintType == ConstraintType.EQUALS) {
            if (field.valueType == uint8(ValueType.INT)) {
                bool ok = field.intValue == c.expectedValue;
                return (ok, ok ? bytes32("OK") : bytes32("EQUALS_FAIL"));
            }

            if (field.valueType == uint8(ValueType.HASH)) {
                bool ok = field.hashValue == c.expectedHash;
                return (ok, ok ? bytes32("OK") : bytes32("EQUALS_FAIL"));
            }

            if (field.valueType == uint8(ValueType.ADDRESS)) {
                address expectedAddr = address(uint160(uint256(c.expectedHash)));
                bool ok = field.addrValue == expectedAddr;
                return (ok, ok ? bytes32("OK") : bytes32("EQUALS_FAIL"));
            }

            if (field.valueType == uint8(ValueType.BOOL)) {
                bool expectedBool = c.expectedValue != 0;
                bool ok = field.boolValue == expectedBool;
                return (ok, ok ? bytes32("OK") : bytes32("EQUALS_FAIL"));
            }

            return (false, bytes32("UNSUPPORTED_TYPE"));
        }

        if (c.constraintType == ConstraintType.RANGE) {
            if (field.valueType != uint8(ValueType.INT)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            bool ok = field.intValue >= c.minValue && field.intValue <= c.maxValue;
            return (ok, ok ? bytes32("OK") : bytes32("RANGE_FAIL"));
        }

        if (c.constraintType == ConstraintType.HASH_MATCH) {
            if (field.valueType != uint8(ValueType.HASH)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            bool ok = field.hashValue == c.expectedHash;
            return (ok, ok ? bytes32("OK") : bytes32("HASH_MISMATCH"));
        }

        if (c.constraintType == ConstraintType.DEADLINE) {
            if (field.valueType != uint8(ValueType.INT)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            if (field.intValue < 0) {
                return (false, bytes32("INVALID_TIMESTAMP"));
            }

            uint256 deliveredAt = uint256(field.intValue);
            bool ok = deliveredAt <= deadline && block.timestamp <= deadline;
            return (ok, ok ? bytes32("OK") : bytes32("DEADLINE_FAIL"));
        }

        if (c.constraintType == ConstraintType.SIGNATURE_VALID) {
            if (field.valueType != uint8(ValueType.ADDRESS)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            address expectedSigner = address(uint160(uint256(c.expectedHash)));
            bool ok = field.addrValue == expectedSigner;
            return (ok, ok ? bytes32("OK") : bytes32("SIGNER_MISMATCH"));
        }

        if (c.constraintType == ConstraintType.ENUM_MEMBER) {
            if (field.valueType != uint8(ValueType.HASH)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            for (uint256 i = 0; i < c.enumMembers.length; i++) {
                if (field.hashValue == c.enumMembers[i]) {
                    return (true, bytes32("OK"));
                }
            }

            return (false, bytes32("NOT_IN_ENUM"));
        }

        if (c.constraintType == ConstraintType.FRESHNESS) {
            if (field.valueType != uint8(ValueType.INT)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            if (field.intValue < 0) {
                return (false, bytes32("INVALID_TIMESTAMP"));
            }

            uint256 fieldTs = uint256(field.intValue);
            bool ok = block.timestamp >= fieldTs &&
                (block.timestamp - fieldTs) <= uint256(c.expectedValue);

            return (ok, ok ? bytes32("OK") : bytes32("STALE_DATA"));
        }

        if (c.constraintType == ConstraintType.TIMESTAMP_WINDOW) {
            if (field.valueType != uint8(ValueType.INT)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            bool ok = field.intValue >= c.minValue && field.intValue <= c.maxValue;
            return (ok, ok ? bytes32("OK") : bytes32("TIMESTAMP_WINDOW_FAIL"));
        }

        if (c.constraintType == ConstraintType.MERKLE_ROOT_MATCH) {
            if (field.valueType != uint8(ValueType.HASH)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            bool ok = field.hashValue == c.expectedHash;
            return (ok, ok ? bytes32("OK") : bytes32("MERKLE_ROOT_MISMATCH"));
        }

        if (c.constraintType == ConstraintType.SIGNER_IN_ALLOWLIST) {
            if (field.valueType != uint8(ValueType.ADDRESS)) {
                return (false, bytes32("TYPE_MISMATCH"));
            }

            bytes32 signerAsBytes32 = bytes32(uint256(uint160(field.addrValue)));

            for (uint256 i = 0; i < c.enumMembers.length; i++) {
                if (signerAsBytes32 == c.enumMembers[i]) {
                    return (true, bytes32("OK"));
                }
            }

            return (false, bytes32("SIGNER_NOT_ALLOWED"));
        }

        return (false, bytes32("UNKNOWN_CONSTRAINT"));
    }
}

